#include <bits/stdc++.h>
using namespace std;

int n,m,dis[40004];
char s[40004];
queue<int> q;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        for(int j=1;j<=m;j++)
            if(s[j]=='1')
                q.push((i-1)*m+j),dis[(i-1)*m+j]=1;
    }
    while(q.size()){
        int x=q.front();
        q.pop();
        if(x%m!=1 && !dis[x-1])
            dis[x-1]=dis[x]+1,q.push(x-1);
        if(x%m!=0 && !dis[x+1])
            dis[x+1]=dis[x]+1,q.push(x+1);
        if(x<=n*m-m && !dis[x+m])
            dis[x+m]=dis[x]+1,q.push(x+m);
        if(x>m && !dis[x-m])
            dis[x-m]=dis[x]+1,q.push(x-m);
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++)
            printf("%d ",dis[(i-1)*m+j]-1);
        puts("");
    }
    return 0;
}
